use std::convert::{From, Into};
use std::fmt;

struct BrokenData(i32);

impl fmt::Display for BrokenData {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "BrokenValue({})", self.0)
    }
}

impl From<String> for BrokenData {
    fn from(s: String) -> Self {
        match s.parse::<i32>() {
            Ok(val) => BrokenData(val),
            Err(_) => BrokenData(-1),
        }
    }
}

struct SafeNumber(u64);

impl From<BrokenData> for SafeNumber {
    fn from(data: BrokenData) -> Self {
        if data.0 >= 0 {
            SafeNumber(data.0 as u64)
        } else {
            panic!("Cannot convert negative value to SafeNumber");
        }
    }
}

fn main() {
    let input_string = String::from("123");
    let broken: BrokenData = input_string.into();
    println!("Initial conversion result: {}", broken);

    let safe_num: SafeNumber = broken.into();
    println!("Final safe number: {}", safe_num.0);

    let bad_input_string = String::from("hello");
    let failed_conversion: BrokenData = bad_input_string.into();
    println!("Failed conversion result: {}", failed_conversion);

    if failed_conversion.0 == -1 {
        println!("Successfully caught the failure case.");
    }
}

use std::fmt::{self, Display};
use std::convert::{From, TryFrom};

struct ProductCode(String);

impl From<&str> for ProductCode {
    fn from(s: &str) -> Self {
        ProductCode(s.to_uppercase())
    }
}

#[derive(Debug)]
enum ConversionError {
    InvalidFormat(&'static str),
    EmptyInput,
}

impl Display for ConversionError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            ConversionError::InvalidFormat(msg) => write!(f, "Bad data: {}", msg),
            ConversionError::EmptyInput => write!(f, "Cannot convert empty value."),
        }
    }
}

impl std::error::Error for ConversionError {}

struct ValidatedDate(u32);

impl TryFrom<&str> for ValidatedDate {
    type Error = ConversionError;

    fn try_from(value: &str) -> Result<Self, Self::Error> {
        if value.is_empty() {
            return Err(ConversionError::EmptyInput);
        }
        // Simplified logic for demonstration: assume length 5 means valid date component
        if value.len() < 5 {
            return Err(ConversionError::InvalidFormat("Must be at least 5 characters long"));
        }
        let components: Vec<&str> = value.split('-').collect();
        if components.len() != 3 {
            return Err(ConversionError::InvalidFormat("Date must use X-Y-Z format"));
        }
        // In a real scenario, we would parse and validate month/day ranges here.
        let day_str = components[0];
        match day_str.parse::<u32>() {
            Ok(day) => Ok(ValidatedDate(day)),
            Err(_) => Err(ConversionError::InvalidFormat("Day component is not a number"))
        }
    }
}

fn main() {
    let raw_input = "2023-12-25";

    // 1. From trait usage (simple conversion)
    let code: ProductCode = raw_input.into();
    println!("Product Code from string: {:?}", code);

    // 2. TryFrom/TryInto usage (fallible conversion)
    match <ValidatedDate as TryFrom<&str>>::try_from(raw_input) {
        Ok(date) => println!("Successfully parsed date: {:?}", date),
        Err(e) => eprintln!("Failed to parse date: {}", e),
    }

    // 3. Failed conversion attempt
