    match <ValidatedDate as TryFrom<&str>>::try_from(bad_input) {
        Ok(_) => (),
        Err(e) => println!("Caught expected error for bad input: {}", e),
    }
}

use std::fmt::{self, Display};

trait Convertible<T> {
    fn to_inner(self) -> T;
}

struct StringWrapper(String);

impl From<&str> for StringWrapper {
    fn from(s: &str) -> Self {
        StringWrapper(s.to_string())
    }
}

impl Display for StringWrapper {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.0)
    }
}

trait ToDisplay {
    fn to_display_string(self) -> String;
}

impl<T: ToString> ToDisplay for T {
    fn to_display_string(self) -> String {
        self.to_string()
    }
}

impl Convertible<String> for StringWrapper {
    fn to_inner(self) -> String {
        self.0
    }
}

fn process_data<A, B>(input_a: A, input_b: B) where A: Convertible<String>, B: ToDisplay {
    let inner_a = input_a.to_inner();
    let display_b = input_b.to_display_string();
    println!("Processed: {} and {}", inner_a, display_b);
}

fn main() {
    let raw_str: &str = "Hello";
    let wrapped_data: StringWrapper = raw_str.into();

    let num: i32 = 42;

    process_data(wrapped_data, num);
}

use std::fmt::{self, Display};
use std::str::FromStr;

struct Count(i32);

impl From<String> for Count {
    fn from(s: String) -> Self {
        match i32::from_str(&s) {
            Ok(num) => Count(num),
            Err(_) => panic!("Invalid string format provided for count conversion.")
        }
    }
}

impl From<&str> for Count {
    fn from(s: &str) -> Self {
        match i32::from_str(s) {
            Ok(num) => Count(num),
            Err(_) => panic!("Invalid string slice format provided for count conversion.")
        }
    }
}

impl Display for Count {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{} items", self.0)
    }
}

fn main() {
    let string_input = String::from("42");
    let count_from_string: Count = string_input.into();
    println!("Converted from String: {}", count_from_string);

    let slice_input = "100";
    let count_from_slice: Count = slice_input.into();
    println!("Converted from &str: {}", count_from_slice);

    let result_count = Count::from(String::from("5"));
    println!("Another conversion check: {}", result_count); 
}
